    private fun get(i: Int): Long = when {
        i < D1_START -> D0[i]
        i < D2_START -> D1[i - D1_START]
        else         -> D2[i - D2_START]
    }

    private fun entryJd(i: Int): Long = BASE_JD + get(i) / MOD_JD

    fun toLunar(y: Int, m: Int, d: Int): LunarDate? {
        val target: Long = julianDay(y, m, d)
        var lo = 0; var hi = SIZE - 1; var idx = -1
        while (lo <= hi) {
            val mid = (lo + hi) ushr 1
            if (entryJd(mid) <= target) { idx = mid; lo = mid + 1 }
            else hi = mid - 1
        }
        if (idx < 0) return null
        val v:   Long = get(idx)
        val jd:  Long = BASE_JD + v / MOD_JD
        val day: Int  = (target - jd + 1L).toInt()
        if (day < 1 || day > 30) return null
        val lyOff: Int     = ((v % MOD_JD) / MOD_LY).toInt()
        val lm:    Int     = ((v % MOD_LY) / MOD_LM).toInt()
        val il:    Boolean = (v % MOD_LM) == 1L
        return LunarDate(1900 + lyOff, lm, day, il)
    }

    private fun julianDay(y: Int, m: Int, d: Int): Long {
        var my = y.toDouble()
        var mm = m.toDouble()
        if (mm <= 2.0) { my -= 1.0; mm += 12.0 }
        val a: Int  = (my / 100.0).toInt()
        val b: Int  = 2 - a + a / 4
        val p1: Long = (365.25  * (my + 4716.0)).toLong()
        val p2: Long = (30.6001 * (mm +    1.0)).toLong()
        return p1 + p2 + d.toLong() + b.toLong() - 1524L
    }

    fun monthName(m: Int, isLeap: Boolean): String {
        val n = arrayOf("","正","二","三","四","五","六","七","八","九","十","十一","十二")
        return (if (isLeap) "閏" else "") + n[m] + "月"
    }

    fun dayName(d: Int): String {
        val u = arrayOf("","一","二","三","四","五","六","七","八","九","十")
        return when {
            d <= 9  -> "初" + u[d]
            d == 10 -> "初十"
            d <= 19 -> "十" + u[d - 10]
            d == 20 -> "二十"
            d <= 29 -> "廿" + u[d - 20]
            else    -> "三十"
        }
    }
